import{_ as a,o as t,c as o,a2 as s}from"./chunks/framework.CHSDihme.js";const i="/claude-code-token-free/assets/01-search-botfather.12SNTJo9.png",l="/claude-code-token-free/assets/02-newbot-command.Cy-4xWeS.png",r="/claude-code-token-free/assets/03-bot-token.DsBftkcf.png",d="/claude-code-token-free/assets/04-fill-bot-token.BcoC4D7i.png",n="/claude-code-token-free/assets/05-generate-pairing-code.DYe28l_c.png",c="/claude-code-token-free/assets/06-pair-success.CsYp2nkn.png",f=JSON.parse('{"title":"Telegram 接入","description":"","frontmatter":{},"headers":[],"relativePath":"im/telegram.md","filePath":"im/telegram.md","lastUpdated":1780310001000}'),h={name:"im/telegram.md"};function p(k,e,u,m,g,b){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="telegram-接入" tabindex="-1">Telegram 接入 <a class="header-anchor" href="#telegram-接入" aria-label="Permalink to &quot;Telegram 接入&quot;">​</a></h1><blockquote><p>Telegram Adapter 的接入教程。找 BotFather 拿 Token，桌面端填完配对即可。</p></blockquote><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><p>Telegram 方案适合个人私聊远程使用。当前实现只处理 <code>private chat</code>，不处理群聊。</p><p>实现入口：<code>adapters/telegram/index.ts</code></p><h2 id="1-创建-telegram-机器人" tabindex="-1">1. 创建 Telegram 机器人 <a class="header-anchor" href="#1-创建-telegram-机器人" aria-label="Permalink to &quot;1. 创建 Telegram 机器人&quot;">​</a></h2><p>在 Telegram 里搜索官方账号 <strong>@BotFather</strong>：</p><p><img src="'+i+'" alt="搜索 BotFather"></p><p>给它发送 <code>/newbot</code>：</p><p><img src="'+l+'" alt="发送 /newbot"></p><p>按提示走完三步：</p><ul><li><strong>取一个机器人名称</strong>，例如 <code>ClaudeCodeHaha机器人</code></li><li><strong>取一个机器人用户名</strong>，要求全英文字母，且必须以 <code>_bot</code> 结尾，例如 <code>jiang_cc_hah_bot</code></li><li>创建成功后，复制 BotFather 返回的 <strong>Bot Token</strong></li></ul><p><img src="'+r+'" alt="复制 Bot Token"></p><h2 id="2-在-claude-code-token-free-桌面端填写" tabindex="-1">2. 在 Claude Code token free 桌面端填写 <a class="header-anchor" href="#2-在-claude-code-token-free-桌面端填写" aria-label="Permalink to &quot;2. 在 Claude Code token free 桌面端填写&quot;">​</a></h2><h3 id="21-填写-bot-token" tabindex="-1">2.1 填写 Bot Token <a class="header-anchor" href="#21-填写-bot-token" aria-label="Permalink to &quot;2.1 填写 Bot Token&quot;">​</a></h3><p>打开桌面端 <code>设置 → IM 接入 → Telegram</code>，把上一步的 Bot Token 填进去：</p><p><img src="'+d+'" alt="填写 Bot Token"></p><h3 id="22-生成配对码" tabindex="-1">2.2 生成配对码 <a class="header-anchor" href="#22-生成配对码" aria-label="Permalink to &quot;2.2 生成配对码&quot;">​</a></h3><p>点击「生成配对码」按钮，拿到 6 位配对码后点击保存：</p><p><img src="'+n+'" alt="生成配对码"></p><h2 id="3-机器人与桌面端配对" tabindex="-1">3. 机器人与桌面端配对 <a class="header-anchor" href="#3-机器人与桌面端配对" aria-label="Permalink to &quot;3. 机器人与桌面端配对&quot;">​</a></h2><p>随便给刚才创建的机器人发送一条消息，按提示输入配对码。看到下面的配对成功提示，就可以从手机 Telegram 远程驱动桌面端 Claude Code token free 了：</p><p><img src="'+c+`" alt="配对成功"></p><h2 id="支持的命令" tabindex="-1">支持的命令 <a class="header-anchor" href="#支持的命令" aria-label="Permalink to &quot;支持的命令&quot;">​</a></h2><ul><li><code>/start</code> — 显示帮助和可用命令</li><li><code>/projects</code> — 切换项目，重新显示最近项目列表</li><li><code>/status</code> — 查看当前会话的项目、模型、运行状态和任务摘要</li><li><code>/clear</code> — 清空当前会话上下文，保留项目绑定</li><li><code>/new</code> — 清空当前 chat 绑定的 session，并重新选择项目</li><li><code>/help</code> — 显示当前可用命令</li><li><code>/stop</code> — 向当前 session 发送 <code>stop_generation</code></li></ul><h2 id="权限审批" tabindex="-1">权限审批 <a class="header-anchor" href="#权限审批" aria-label="Permalink to &quot;权限审批&quot;">​</a></h2><p>当 Claude 请求敏感权限时，Telegram adapter 会发带按钮的消息：</p><ul><li><code>✅ 允许</code></li><li><code>♾️ 永久允许</code></li><li><code>❌ 拒绝</code></li></ul><p>点击后 adapter 会把结果通过 <code>permission_response</code> 回传给 Desktop server。</p><h2 id="返回消息的表现" tabindex="-1">返回消息的表现 <a class="header-anchor" href="#返回消息的表现" aria-label="Permalink to &quot;返回消息的表现&quot;">​</a></h2><p>Telegram 侧有一层流式缓冲：</p><ul><li>thinking 时先发占位消息</li><li>text delta 逐步累积</li><li>完成时按 4000 字分片发送</li></ul><p>对应公共模块：</p><ul><li><code>adapters/common/message-buffer.ts</code></li><li><code>adapters/common/format.ts</code></li><li><code>adapters/common/ws-bridge.ts</code></li></ul><h2 id="启动-adapter" tabindex="-1">启动 adapter <a class="header-anchor" href="#启动-adapter" aria-label="Permalink to &quot;启动 adapter&quot;">​</a></h2><p>桌面端会自动把 adapter 作为 sidecar 拉起。如果你在本地开发，需要手动启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> adapters</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><h2 id="环境变量覆盖可选" tabindex="-1">环境变量覆盖（可选） <a class="header-anchor" href="#环境变量覆盖可选" aria-label="Permalink to &quot;环境变量覆盖（可选）&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> TELEGRAM_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;123456:ABC-DEF...&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADAPTER_SERVER_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ws://127.0.0.1:3456&quot;</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="bot-启动时报缺少-token" tabindex="-1">bot 启动时报缺少 token <a class="header-anchor" href="#bot-启动时报缺少-token" aria-label="Permalink to &quot;bot 启动时报缺少 token&quot;">​</a></h3><p>说明 <code>TELEGRAM_BOT_TOKEN</code> 和 <code>~/.claude/adapters.json</code> 里的 <code>telegram.botToken</code> 都没有生效。</p><h3 id="能打开设置页但-bot-不工作" tabindex="-1">能打开设置页但 bot 不工作 <a class="header-anchor" href="#能打开设置页但-bot-不工作" aria-label="Permalink to &quot;能打开设置页但 bot 不工作&quot;">​</a></h3><p>Webapp 只负责配置，不会自动拉起 <code>bun run telegram</code>（桌面端发布版会通过 sidecar 自动拉起）。</p><h3 id="发消息提示未授权" tabindex="-1">发消息提示未授权 <a class="header-anchor" href="#发消息提示未授权" aria-label="Permalink to &quot;发消息提示未授权&quot;">​</a></h3><ul><li>是否已经在桌面端生成配对码</li><li>配对码是否在 60 分钟有效期内</li><li>是否把码发到了正确的 bot 私聊</li><li>连续输错会有速率限制，等几分钟再试</li></ul><h3 id="每次重启后会话丢失" tabindex="-1">每次重启后会话丢失 <a class="header-anchor" href="#每次重启后会话丢失" aria-label="Permalink to &quot;每次重启后会话丢失&quot;">​</a></h3><p>检查 <code>~/.claude/adapter-sessions.json</code> 是否能正常写入，以及 Desktop server 的 session 是否仍存在。</p><h2 id="源码入口" tabindex="-1">源码入口 <a class="header-anchor" href="#源码入口" aria-label="Permalink to &quot;源码入口&quot;">​</a></h2><ul><li><code>adapters/telegram/index.ts</code></li><li><code>adapters/common/pairing.ts</code></li><li><code>adapters/common/session-store.ts</code></li><li><code>adapters/common/ws-bridge.ts</code></li><li><code>adapters/common/http-client.ts</code></li></ul>`,50)])])}const q=a(h,[["render",p]]);export{f as __pageData,q as default};
